const Web3 = require('web3');
const web3 = new Web3(new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'));

async function sendTransaction(privateKey, toAddress, amount) {
    const account = web3.eth.accounts.privateKeyToAccount(privateKey);
    const nonce = await web3.eth.getTransactionCount(account.address);

    const tx = {
        from: account.address,
        to: toAddress,
        value: web3.utils.toWei(amount.toString(), 'ether'),
        gas: 21000,
        gasPrice: web3.utils.toWei('5', 'gwei'),
        nonce: nonce
    };

    const signedTx = await web3.eth.accounts.signTransaction(tx, privateKey);
    const receipt = await web3.eth.sendSignedTransaction(signedTx.rawTransaction);

    return receipt;
}

async function interactWithContract(privateKey, contractAddress, abi, method, params) {
    const account = web3.eth.accounts.privateKeyToAccount(privateKey);
    const contract = new web3.eth.Contract(abi, contractAddress, { from: account.address });

    const tx = await contract.methods[method](...params).send({ gas: 21000, gasPrice: web3.utils.toWei('5', 'gwei') });
    return tx;
}

